        // After modification: first k/2 elements are 0, next k/2 are 1
        // So, we need to subtract the original contribution of the first k/2 elements and add 0
        // And add the contribution of the next k/2 elements (which were originally 1)
        for (let j = 0; j < k; j++) {
            if (j < k / 2) {
                // Original contribution was -1 * prices[i + j]
                // After modification, it's 0 * prices[i + j] = 0
                change -= strategy[i + j] * prices[i + j];
            } else {
                // Original contribution was 1 * prices[i + j]
                // After modification, it's 1 * prices[i + j] (no change)
                // So no change needed
            }
        }
        // Update the max profit
        maxProfit = Math.max(maxProfit, profit + change);
    }

    return maxProfit;
}

